mapper.select:
SELECT CASE WHEN EXISTS ( SELECT 1 FROM user WHERE refer_id IN
#{keys}
GROUP BY refer_id HAVING COUNT(*) > 1 ) THEN 1 ELSE 0 END AS result;

SELECT IFNULL(SUM(u.team_amount),0) AS sum_amount_exclude_max
FROM `user` u
         LEFT JOIN (
    SELECT id
    FROM `user`
    WHERE refer_id = #{userId}
    ORDER BY (team_amount) DESC
        LIMIT 1
) AS max_user ON u.id = max_user.id
WHERE u.refer_id = #{userId} AND max_user.id IS NULL;

SELECT IFNULL(SUM(u.team_amount),0) AS sum_amount_exclude_max
FROM `user` u
         LEFT JOIN (
    SELECT id
    FROM `user`
    WHERE refer_id = #{userId}
    ORDER BY (team_amount) DESC
        LIMIT 1
) AS max_user ON u.id = max_user.id
WHERE u.refer_id = #{userId} AND max_user.id IS NULL;

select u.id from `user` u
where flag = 1
 and id>#{startId} 
 and team_amount> #{minTeamAmount} 
order by u.id asc
limit #{size}
